// RegisterUser is the resolver for the registerUser field.
func (r *mutationResolver) RegisterUser(ctx context.Context, email string, password string) (*model.User, error) {
	if !helpers.IsValidEmail(email) {
		return nil, fmt.Errorf("email is invalid, please provide a valid email")
	}
	if !helpers.IsUniqEmail(email) {
		return nil, fmt.Errorf("email already exists")
	}
	if !helpers.IsValidPassword(password) {
		return nil, fmt.Errorf("password should be at least 6 symbols, one letter")
	}

	hashedPassword, err := helpers.HashPassword(password)
	if err != nil {
		log.Println(err)
		return nil, fmt.Errorf("internal server error (hashing)")
	}

	id, createdAt, err := database.CreateUser(ctx, r.DB, email, hashedPassword)
	if err != nil {
		log.Println(err)
		return nil, fmt.Errorf("internal server error (db)")
	}

	_, profilePicture := database.GetUserNamePhotoURL(ctx, r.DB, id)

	//    Note: gqlgen models are pointers
	return &model.User{
		UserID:         id,
		Email:          email,
		CreatedAt:      createdAt,
		ProfilePicture: &profilePicture,
	}, nil
}

// LoginUser is the resolver for the loginUser field.
func (r *mutationResolver) LoginUser(ctx context.Context, email string, password string) (*model.LoginResponse, error) {
	userID, pwHash, err := database.GetUserByEmail(ctx, r.DB, email)

	if errors.Is(err, pgx.ErrNoRows) {
		return nil, fmt.Errorf("user does not exist")
	}

	if err != nil {
		return nil, fmt.Errorf("internal server error (db)")
	}

	if !helpers.IsCorrectPassword(pwHash, password) {
		return nil, fmt.Errorf("invalid email or password")
	}

	user, err := r.GetUser(ctx, userID)
	if err != nil {
		return nil, err
	}

	access, err := helpers.MakeAccessToken(userID)
	if err != nil {
		return nil, fmt.Errorf("internal server error(access token)")
	}

	return &model.LoginResponse{
		Token: access,
		User:  user,
	}, nil
}

