// Recommendations is the resolver for the recommendations field.
func (r *queryResolver) Recommendations(ctx context.Context, limit *int32, offset *int32) ([]*model.User, error) {
	userID, ok := middleware.GetUserIDFromContext(ctx)
	if !ok {
		return nil, gqlerror.Errorf("unauthorized")
	}

	// 3. Profile Completion Check (Same as before)
	percent, err := database.GetProfileCompletionPercent(ctx, r.DB, userID)
	if err != nil {
		log.Println(err)
		return nil, gqlerror.Errorf("db error")
	}

	if percent < 100 {
		return nil, gqlerror.Errorf("Profile filled only %.1f%% — please complete your profile before viewing recommendations.", percent)
	}

	currentProfile, err := database.GetMatchingProfile(ctx, r.DB, userID)
	if err != nil || currentProfile == nil {
		log.Println(err)
		return nil, gqlerror.Errorf("db error")

	}

	currentPrefs, err := database.GetUserMatchingPreferences(ctx, r.DB, userID)
	if err != nil {
		log.Println(err)
		return nil, gqlerror.Errorf("db error")

	}

	candidates, err := database.GetPotentialMatches(ctx, r.DB, userID)
	if err != nil {
		log.Println(err)
		return nil, gqlerror.Errorf("db error")

	}
	matches := services.CalculateMatchingScores(currentProfile, currentPrefs, candidates, ctx)

	if len(matches) > 10 {
		matches = matches[:*limit]
	}

	var recommendations []string

	for _, match := range matches {
		recommendations = append(recommendations, string(match.UserID))
	}

	var users []*model.User

	for _, recommendedUserId := range recommendations {
		user, err := r.GetUser(ctx, recommendedUserId)
		if err != nil {
			return nil, err
		}

		profile, err := r.GetProfile(ctx, recommendedUserId)
		if err != nil {
			return nil, err
		}

		bio, err := r.GetBio(ctx, recommendedUserId)
		if err != nil {
			return nil, err
		}

		user.Profile = profile
		user.Bio = bio
		users = append(users, user)
	}

	return users, nil
}

// ConnectReguests is the resolver for the connectReguests field.
func (r *queryResolver) ConnectReguests(ctx context.Context, limit *int32, offset *int32) ([]*model.User, error) {
	userID, ok := middleware.GetUserIDFromContext(ctx)
	if !ok {
		return nil, gqlerror.Errorf("unauthorized")
	}

	// 3. Profile Completion Check (Same as before)
	percent, err := database.GetProfileCompletionPercent(ctx, r.DB, userID)
	if err != nil {
		log.Println(err)
		return nil, gqlerror.Errorf("db error")
	}

	if percent < 100 {
		return nil, gqlerror.Errorf("Profile is not complete")
	}

	// Get connection requests (with connection IDs)
	connectionRequests, err := database.GetIncomingConnectionRequests(ctx, r.DB, userID)
	if err != nil {
		return nil, gqlerror.Errorf("db error")
	}

	// Extract requester user IDs for response
	var users []*model.User

	for _, conn := range connectionRequests {
		user, err := r.GetUser(ctx, conn.RequesterUserID)
		if err != nil {
			return nil, err
		}

		profile, err := r.GetProfile(ctx, conn.RequesterUserID)
		if err != nil {
			return nil, err
		}

		bio, err := r.GetBio(ctx, conn.RequesterUserID)
		if err != nil {
			return nil, err
		}

		user.Profile = profile
		user.Bio = bio
		users = append(users, user)
	}

	return users, nil
}

